use std::arch::x86_64::*;

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    assert_eq!(a.len(), b.len());
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512(a, b) };
        }
    }
    // fallback scalar
    l2_distance_scalar(a, b)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    // a and b are 128 elements each
    let mut acc = _mm512_setzero_ps();
    let mut i = 0;
    while i < a.len() {
        // load 16 floats from a and b
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        // diff * diff + acc
        acc = _mm512_fmadd_ps(diff, diff, acc);
        i += 16;
    }
    // horizontal sum across the 16 lanes
    let sum = _mm512_reduce_add_ps(acc); // requires AVX512DQ
    (sum as f64).sqrt()
}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for (x, y) in a.iter().zip(b) {
        let diff = *x as f64 - *y as f64;
        sum += diff * diff;
    }
    sum.sqrt()
}

// Fallback for non-x86_64
#[cfg(not(target_arch = "x86_64"))]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for (x, y) in a.iter().zip(b) {
        let diff = *x as f64 - *y as f64;
        sum += diff * diff;
    }
    sum.sqrt()
}"}

{"path": "src/db.rs", "content": "use crate::api::*;
use rayon::prelude::*;
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use std::sync::RwLock;

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    data: RwLock<Vec<f32>>, // flat storage, each vector 128 consecutive f32
    dim: usize,
}

#[derive(PartialEq)]
struct Candidate {
    id: u64,
    distance: f64,
}

impl Eq for Candidate {}

impl PartialOrd for Candidate {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Reverse ordering: larger distance is "less" for max-heap
        other.distance.partial_cmp(&self.distance)
    }
}

impl Ord for Candidate {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap_or(Ordering::Equal)
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            ids: RwLock::new(Vec::new()),
            data: RwLock::new(Vec::new()),
            dim: 128,
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), self.dim);
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        ids.push(id);
        data.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        let start = ids.len();
        for (id, vec) in vectors {
            assert_eq!(vec.len(), self.dim);
            ids.push(id);
            data.extend_from_slice(&vec);
        }
        ids.len() - start
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(vector.len(), self.dim);
        let ids = self.ids.read().unwrap();
        let data = self.data.read().unwrap();
        let n = ids.len();
        let dim = self.dim;
        let k = top_k as usize;

        // If k is large relative to n, fallback to sorting
        if k >= n {
            let mut distances: Vec<SearchResult> = (0..n)
                .into_par_iter()
                .map(|i| {
                    let start = i * dim;
                    let dist = crate::distance::l2_distance(vector, &data[start..start + dim]);
                    SearchResult { id: ids[i], distance: dist }
                })
                .collect();
            distances.par_sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
            return distances;
        }

        // Parallel top-k using binary heap per thread, then merge
        let heaps = (0..n)
            .into_par_iter()
            .fold(
                || BinaryHeap::with_capacity(k),
                |mut heap, i| {
                    let start = i * dim;
                    let dist = crate::distance::l2_distance(vector, &data[start..start + dim]);
                    heap.push(Candidate { id: ids[i], distance: dist });
                    if heap.len() > k {
                        heap.pop(); // remove largest distance (root)
                    }
                    heap
                },
            )
            .reduce(
                || BinaryHeap::with_capacity(k),
                |mut heap1, heap2| {
                    for cand in heap2.into_vec() {
                        heap1.push(cand);
                        if heap1.len() > k {
                            heap1.pop();
                        }
                    }
                    heap1
                },
            );

        // Convert heap to sorted vec ascending by distance
        let mut results: Vec<SearchResult> = heaps
            .into_vec()
            .into_iter()
            .map(|c| SearchResult { id: c.id, distance: c.distance })
            .collect();
        results.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}"}

