    let va0 = _mm512_loadu_ps(a_ptr);
    let vb0 = _mm512_loadu_ps(b_ptr);
    let diff0 = _mm512_sub_ps(va0, vb0);
    acc0 = _mm512_fmadd_ps(diff0, diff0, acc0);

